arguments.argument:
event_inherited()
if global.gamePaused=false
{
  x=oPlayer1.x
  y=oPlayer1.y
  image_xscale=oPlayer1.image_xscale
  image_index=oPlayer1.image_index
  
  oPlayer1.xVel=10*oPlayer1.image_xscale
  oPlayer1.yVel=7
  
  decayTime-=1
  if decayTime=15 {oPlayer1.image_index=1}
  if decayTime<=0
  {
    instance_destroy()
  }
}
